from openai import OpenAI
import json
import subprocess
import tempfile
import os

class CodeExecutionAgent:
    """Agent that can generate and execute code."""

    def __init__(self):
        self.client = OpenAI()

    def generate_code(self, task: str) -> str:
        """Generate Python code for a task."""
        response = self.client.chat.completions.create(
            model="gpt-5",
            messages=[
                {"role": "system", "content": "Generate Python code. Only output code, no explanation."},
                {"role": "user", "content": task}
            ]
        )
        code = response.choices[0].message.content
        # Clean up code blocks
        if "```python" in code:
            code = code.split("```python")[1].split("```")[0]
        return code.strip()

    def execute_code(self, code: str, timeout: int = 30) -> dict:
        """Execute code in a subprocess."""
        with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as f:
            f.write(code)
            temp_path = f.name

        try:
            result = subprocess.run(
                ['python', temp_path],
                capture_output=True,
                text=True,
                timeout=timeout
            )
            return {
                "success": result.returncode == 0,
                "stdout": result.stdout,
                "stderr": result.stderr
            }
        except subprocess.TimeoutExpired:
            return {"success": False, "error": "Execution timed out"}
        finally:
            os.unlink(temp_path)

    def interpret_result(self, task: str, code: str, result: dict) -> str:
        """Interpret execution results."""
        if not result["success"]:
            prompt = f"Task: {task}\nCode failed: {result.get('stderr', result.get('error', ''))}\n\nExplain the error and suggest a fix."
        else:
            prompt = f"Task: {task}\nCode: {code}\nOutput: {result['stdout']}\n\nSummarize the results."

        response = self.client.chat.completions.create(
            model="gpt-5",
            messages=[{"role": "user", "content": prompt}]
        )
        return response.choices[0].message.content

    def run(self, task: str, max_retries: int = 3) -> str:
        """Run the full code execution loop."""
        for attempt in range(max_retries):
            print(f"\nAttempt {attempt + 1}:")

            # Generate code
            code = self.generate_code(task)
            print(f"Generated code:\n{code}\n")

            # Execute code
            result = self.execute_code(code)
            print(f"Execution result: {result}")

            # Interpret and retry if failed
            if result["success"]:
                return self.interpret_result(task, code, result)

            # Modify task to include error feedback
            task = f"{task}\n\nPrevious attempt failed: {result.get('stderr', '')}\nFix the code."

        return "Failed after max retries"

# Usage
agent = CodeExecutionAgent()
result = agent.run("Calculate the first 20 Fibonacci numbers and print them")
print(result)
